SELECT COUNT(*) AS track_count
FROM tracks
WHERE duration_ms > (SELECT AVG(duration_ms) FROM tracks);

SELECT COUNT(track_id)
FROM tracks
WHERE explicit = 1 AND track_id NOT IN (SELECT track_id FROM playlist_tracks);

SELECT SUM(a.play_count) AS total_play_count
FROM analytics a
JOIN recommendations r ON a.track_id = r.track_id;

SELECT recommendation_id, user_id, track_id, recommendation_date
FROM recommendations
WHERE recommendation_date = (SELECT MAX(recommendation_date) FROM recommendations);

SELECT track_id, duration_ms, danceability
FROM tracks
WHERE danceability > 0.8;
